import static org.junit.jupiter.api.Assertions.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_withValidFile() throws IOException {
        File tempFile = File.createTempFile("csv", ".tmp");
        tempFile.deleteOnExit();

        // Cast to avoid ambiguity between print(File, Charset) and print(Path, Charset)
        CSVPrinter printer = csvFormat.print((File) tempFile, StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
    }

    @Test
    public void testPrint_withNullFile_shouldThrowException() {
        assertThrows(NullPointerException.class, () -> csvFormat.print((File) null, StandardCharsets.UTF_8));
    }

    @Test
    public void testPrint_withNullCharset_shouldThrowException() throws IOException {
        File tempFile = File.createTempFile("csv", ".tmp");
        tempFile.deleteOnExit();

        assertThrows(NullPointerException.class, () -> csvFormat.print(tempFile, null));
    }

    @Test
    public void testPrint_verifyPrinterOutputStreamWriterCharset() throws IOException {
        File tempFile = File.createTempFile("csv", ".tmp");
        tempFile.deleteOnExit();

        CSVPrinter printer = csvFormat.print((File) tempFile, StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
    }
}
